QUIZ4 = {1: [{'q': 'A 24 VDC circuit draws 0.5 A. What is the load resistance?', 'options': ['12 Ω', '48 Ω', '24 Ω', '0.5 Ω'], 'answer': 1, 'explain': 'R = V/I = 24/0.5 = 48 Ω.'}, {'q': 'In a series circuit, what stays the same at every component?', 'options': ['Voltage', 'Current', 'Resistance', 'Power'], 'answer': 1, 'explain': 'Series current is identical everywhere; voltage divides across the loads.'}, {'q': 'What does a higher AWG number indicate about a wire?', 'options': ['Larger diameter', 'Smaller diameter', 'Higher voltage rating', 'More strands'], 'answer': 1, 'explain': 'AWG is inverse: bigger number = thinner conductor = less current capacity.'}], 2: [{'q': 'What is the correct order of a PLC scan cycle?', 'options': ['Solve logic → read inputs → write outputs', 'Read inputs → solve logic → write outputs', 'Write outputs → read inputs → solve logic', 'Read inputs → write outputs → solve logic'], 'answer': 1, 'explain': 'Every scan: sample inputs, execute the program, then update the output image.'}, {'q': 'A normally-open contact in ladder logic passes power when its bit is:', 'options': ['0 (false)', '1 (true)', 'Toggling', 'Held'], 'answer': 1, 'explain': 'An XIC / NO contact conducts when the referenced bit is true.'}, {'q': 'Which memory holds the real-time state of physical field wiring?', 'options': ['Data files', 'The I/O image table', 'The user program', 'Retentive memory'], 'answer': 1, 'explain': 'The input/output image table mirrors field I/O each scan.'}], 4: [{'q': 'Which sensor detects only metallic targets at short range?', 'options': ['Capacitive', 'Inductive proximity', 'Photoelectric', 'Ultrasonic'], 'answer': 1, 'explain': 'Inductive proximity sensors respond to metal via eddy-current damping.'}, {'q': 'A PNP (sourcing) discrete sensor supplies which signal when active?', 'options': ['Ground/0 V to the load', 'Positive V to the load', 'An analog current', 'A pulse train'], 'answer': 1, 'explain': 'PNP sources positive voltage to the input; NPN sinks to 0 V.'}, {'q': 'A retro-reflective photoeye uses a reflector and detects a part when the beam is:', 'options': ['Reflected back', 'Broken/blocked', 'Doubled', 'Inverted'], 'answer': 1, 'explain': 'The part interrupts the reflected beam, signaling presence.'}], 5: [{'q': 'To maintain constant motor torque, a VFD holds which ratio roughly constant?', 'options': ['Current/frequency', 'Volts/Hertz', 'Power/speed', 'Slip/torque'], 'answer': 1, 'explain': 'Constant V/Hz keeps flux and torque steady across the speed range.'}, {'q': 'What does a VFD DC bus do?', 'options': ['Rectifies then filters AC into DC before the inverter', 'Steps up line voltage', 'Measures motor speed', 'Brakes the motor mechanically'], 'answer': 0, 'explain': 'The rectifier + capacitor bus creates a smooth DC link the inverter switches into variable-frequency AC.'}, {'q': 'Motor slip is the difference between:', 'options': ['Line and load voltage', 'Synchronous and actual rotor speed', 'Start and run current', 'Stator and rotor resistance'], 'answer': 1, 'explain': 'Slip = (Ns − Nr)/Ns; an induction motor must slip to produce torque.'}], 11: [{'q': 'On the hierarchy of controls, which is the MOST effective?', 'options': ['PPE', 'Administrative controls', 'Elimination / design-out the hazard', 'Guarding'], 'answer': 2, 'explain': 'Eliminating the hazard at the source outranks guards, procedures, and PPE.'}, {'q': 'A Category 0 stop per IEC 60204-1 removes power:', 'options': ['After a controlled ramp', 'Immediately/uncontrolled', 'Only to the HMI', 'After a timer'], 'answer': 1, 'explain': 'Cat 0 is an immediate removal of power; Cat 1 is a controlled stop then power removal.'}, {'q': 'Lockout/tagout primarily protects against:', 'options': ['Arc flash only', 'Unexpected energization during service', 'Overcurrent', 'Ground faults'], 'answer': 1, 'explain': 'LOTO isolates and secures energy so equipment cannot start while being serviced.'}], 13: [{'q': 'A PLC timer (TON) times while its rung is:', 'options': ['False', 'True/enabled', 'Toggling', 'Reset'], 'answer': 1, 'explain': 'A TON accumulates while enabled and its DN bit sets when ACC reaches PRE.'}, {'q': 'Which instruction is best for indexing through an array of recipe values?', 'options': ['A one-shot', 'Indirect addressing / indexed pointer', 'A latch', 'A JSR with no args'], 'answer': 1, 'explain': 'Indexed/indirect addressing walks an array element-by-element using a pointer.'}, {'q': 'Structured routines/subroutines mainly improve:', 'options': ['Scan speed only', 'Code organization and reuse', 'I/O count', 'Analog resolution'], 'answer': 1, 'explain': 'Modular routines make programs readable, testable, and reusable.'}], 16: [{'q': 'MTBF stands for:', 'options': ['Mean Time Between Failures', 'Maximum Time Before Fault', 'Mean Test Bench Frequency', 'Minimum Time By Failure'], 'answer': 0, 'explain': 'MTBF = total operating time / number of failures; higher is more reliable.'}, {'q': 'Vibration analysis and thermography are examples of which strategy?', 'options': ['Reactive maintenance', 'Predictive (condition-based) maintenance', 'Run-to-failure', 'Design maintenance'], 'answer': 1, 'explain': 'They monitor condition to predict failures before they happen.'}, {'q': 'Which is a PREVENTIVE (time-based) task rather than predictive?', 'options': ['Greasing bearings on a fixed schedule', 'Trending motor current', 'Oil particle analysis', 'Acoustic leak detection'], 'answer': 0, 'explain': 'Calendar/runtime-based lubrication is classic preventive maintenance.'}], 17: [{'q': 'Wire duct/wireway inside a panel is used primarily to:', 'options': ['Dissipate heat', 'Route and protect conductors neatly', 'Ground the enclosure', 'Mount breakers'], 'answer': 1, 'explain': 'Wireway organizes and protects wiring runs between components.'}, {'q': 'A NEMA 12 enclosure is rated for:', 'options': ['Submersion', 'Dust and dripping liquids (indoor)', 'Explosive atmospheres', 'Outdoor rain only'], 'answer': 1, 'explain': 'NEMA 12 protects against dust, dirt, and dripping non-corrosive liquids indoors.'}, {'q': 'Why derate panel components for ambient temperature?', 'options': ['To save cost', 'Heat reduces current-carrying capacity and lifespan', 'To meet color codes', 'To increase voltage'], 'answer': 1, 'explain': 'Higher ambient temps lower ampacity and stress components, so ratings must be derated.'}]}
